mapper.select:
/** CmmtBoardDao.selectList */
select

from
	cmmt_board
where
	1=1

	and system_id = #{systemId}


		and enabled = #{enabled}


		and board_id = #{boardId}


		and board_nm like '%' || #{boardNm} || '%'

/** CmmtBoardDao.select */
select

from
	cmmt_board
where
	board_id = #{boardId}

mapper.insert:
/** CmmtBoardDao.insert */
insert into cmmt_board (
	board_id
	,system_id
	,board_nm
	,article_cnt
	,enabled
	,web_editor
	,notice_available
	,commentable
	,category
	,category_code_group
	,attachable
	,attachment_size
	,attachment_ext
	,use_shared_url
	,use_thumbnail
	,use_form
	,all_readable
	,creator_id
	,created_dt
	,updater_id
	,updated_dt
) values (
	 #{boardId}
	,#{systemId}
	,#{boardNm}
	,#{articleCnt}
	,#{enabled}
	,#{webEditor}
	,#{noticeAvailable}
	,#{commentable}
	,#{category}
	,#{categoryCodeGroup}
	,#{attachable}
	,#{attachmentSize}
	,#{attachmentExt}
	,#{useSharedUrl}
	,#{useThumbnail}
	,#{useForm}
	,#{allReadable}
	,#{creatorId}
	,#{createdDt}
	,#{updaterId}
	,#{updatedDt}
)

mapper.update:
/** CmmtBoardDao.update */
update cmmt_board set
	 board_id            = #{boardId}
	,system_id           = #{systemId}
	,board_nm            = #{boardNm}
	,article_cnt         = #{articleCnt}
	,enabled             = #{enabled}
	,web_editor          = #{webEditor}
	,notice_available    = #{noticeAvailable}
	,commentable         = #{commentable}
	,category            = #{category}
	,category_code_group = #{categoryCodeGroup}
	,attachable          = #{attachable}
	,attachment_size     = #{attachmentSize}
	,attachment_ext      = #{attachmentExt}
	,use_shared_url      = #{useSharedUrl}
	,use_thumbnail       = #{useThumbnail}
	,use_form            = #{useForm}
	,all_readable        = #{allReadable}
	,creator_id          = #{creatorId}
	,created_dt          = #{createdDt}
	,updater_id          = #{updaterId}
	,updated_dt          = #{updatedDt}
where
	board_id = #{boardId}

mapper.delete:
/** CmmtBoardDao.delete */
delete from
	cmmt_board
where
	board_id = #{boardId}

mapper.update:
/** CmmtBoardDao.updateArticleCnt */
update cmmt_board set
	article_cnt = (select count(*) from cmmt_board_article where board_id = #{boardId})
where
	board_id = #{boardId}
